# Default attributes for 32x32 sprites: 4x4 character cells
DEFAULT_ATTR = "0E"  # paper=blue(1), ink=yellow(6)


def shift_frame(rows, dx=1):
    """Shift all pixel rows horizontally by dx pixels (for animation)."""
    shifted = []
    for row in rows:
        if dx > 0:
            shifted.append("0" * dx + row[:-dx])
        elif dx < 0:
            shifted.append(row[-dx:] + "0" * (-dx))
        else:
            shifted.append(row)
    return shifted


def write_zxp(filename, frame1, frame2, width=32):
    """Write a 2-frame .zxp file."""
    height = len(frame1) + len(frame2)
    lines = [
        "ZX-Paintbrush",
        f"{width}x{height}",
    ]
    lines.extend(frame1)
    lines.extend(frame2)
    lines.append("")
    # Attributes: (width/8) columns x (frame_height/8) rows
    attr_cols = width // 8
    attr_rows = len(frame1) // 8
    for _ in range(attr_rows):
        lines.append(" ".join([DEFAULT_ATTR] * attr_cols))

    path = os.path.join(ASSETS_DIR, filename)
    with open(path, "w") as f:
        f.write("\n".join(lines) + "\n")
    print(f"  Created {path}: {width}x{len(frame1)}, 2 frames")


def main():
    os.makedirs(ASSETS_DIR, exist_ok=True)

    for name, frame1 in SPRITES.items():
        assert len(frame1) == 32, f"{name}: expected 32 rows, got {len(frame1)}"
        for i, row in enumerate(frame1):
            assert len(row) == 32, f"{name} row {i}: expected 32 chars, got {len(row)}"

        # Frame 2: shifted by 1 pixel for animation
        frame2 = shift_frame(frame1, dx=1)
        write_zxp(f"{name}.zxp", frame1, frame2)

    print(f"\nGenerated {len(SPRITES)} placeholder sprite files in {ASSETS_DIR}/")


if __name__ == "__main__":
    main()
